_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = vUvOriginal;
vec2 hor = vec2(1,0)*uTexSize.zw*.7;
vec2 ver = vec2(0,1)*uTexSize.zw*.7;;

vUv += (texture(sampler_noise_lq,vUv*4+rand_frame)-0.5)*0.00;
float dx = texture(sampler_main,vUv+hor).r - texture(sampler_main,vUv-hor).r;
float dy = texture(sampler_main,vUv+ver).r - texture(sampler_main,vUv-ver).r;
vec2 dz = vec2 (dx,dy);


vec3 blur = GetBlur1(fract(vUv));


double3 crisp = texture(sampler_main,vUv+dz*.002);
crisp += - length(dz)*.01-0.014*blur;

ret.r = max(0.3,crisp).r;
ret.b = GetPixel(vUv*1.2).b*0.8;
ret.g = GetPixel(vUv*2).b*22;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  vec2 uv1 = (vUvOriginal-0.5)*uAspect.xy + 0.02*vec2(sin(uTime*0.51),sin(uTime*0.19));
  vec2 p, q = multiply(uv1, mat2(_qa))/zoom;
  vec3 S = 0, C = vec3(12, 2, 3), col, scr;

  for (int i = 0; i < trails; i++)
  {
    float j=i/trails;
    p = q* (1-zz*j)+ 0.053* sin(pow(i+1.,vec2(17,23)/51)*T)*vec2(2,1.5);

    col =  (cos(C*cos(i)) +audioLowSmooth);
    vec2 uvt = p + vec2((j-.5)/8*0,T*(1+fract(i*M_PI)));
    scr = GetPixel(3.25*fract(uvt.yx/uAspect.xy+.5));
    float trail = 1 / length(max(p, p / vec2(2, scr.r * speed)));
    S += (trail*scr.g*(-p.y))*0.3*(i%2);
    S += trail *   0.0015 * col ;
    S += vb/length(p)* (sat(1-pow((BPMtime)%trails-i,2)) +
                       sat(1-pow((BPMtime*2)%trails-i,2))*2*col);
 }
 ret = 1-exp(-(sat(q.x)*vec3(0,0.6,1)*2  + pow(S,1.8)/trails));
//MilkDrop3 Color Mode:
//ret /= vec3(-0.4,1.1,2.8);

  fragColor = ret;
}
